import "dotenv/config";
import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "http://127.0.0.1:8545";
const CHAIN_ID = Number(process.env.CHAIN_ID || 1);
const PRIVATE_KEY = process.env.PRIVATE_KEY;

if (!PRIVATE_KEY) {
  throw new Error("Missing PRIVATE_KEY in environment");
}

const provider = new ethers.JsonRpcProvider(RPC_URL, CHAIN_ID);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export function getProvider() {
  return provider;
}

export function getWallet() {
  return wallet;
}

export async function getNativeBalance(address = wallet.address) {
  return await provider.getBalance(address);
}

export async function sendETH({
  to,
  amountEth,
  gasLimit,
  maxFeePerGasGwei,
  maxPriorityFeePerGasGwei,
  nonce,
  valueWei
}) {
  if (!to) throw new Error("Missing recipient address");
  if (amountEth == null && valueWei == null) {
    throw new Error("Provide amountEth or valueWei");
  }

  const tx = {
    to,
    value: valueWei != null ? BigInt(valueWei) : ethers.parseEther(String(amountEth)),
    chainId: CHAIN_ID
  };

  if (gasLimit != null) tx.gasLimit = BigInt(gasLimit);
  if (nonce != null) tx.nonce = Number(nonce);
  if (maxFeePerGasGwei != null) tx.maxFeePerGas = ethers.parseUnits(String(maxFeePerGasGwei), "gwei");
  if (maxPriorityFeePerGasGwei != null) {
    tx.maxPriorityFeePerGas = ethers.parseUnits(String(maxPriorityFeePerGasGwei), "gwei");
  }

  if (tx.gasLimit == null) {
    tx.gasLimit = await wallet.estimateGas(tx);
  }

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    value: response.value?.toString(),
    blockNumber: receipt?.blockNumber,
    status: receipt?.status
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  if (!contractAddress) throw new Error("Missing contract address");
  if (!abi) throw new Error("Missing contract ABI");
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead({
  contractAddress,
  abi,
  method,
  args = [],
  blockTag
}) {
  const contract = getContract(contractAddress, abi, provider);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method not found: ${method}`);
  }
  return blockTag != null ? await contract[method](...args, { blockTag }) : await contract[method](...args);
}

export async function sendContractTransaction({
  contractAddress,
  abi,
  method,
  args = [],
  valueEth,
  valueWei,
  gasLimit,
  maxFeePerGasGwei,
  maxPriorityFeePerGasGwei,
  nonce
}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method not found: ${method}`);
  }

  const overrides = {};
  if (valueWei != null) overrides.value = BigInt(valueWei);
  if (valueEth != null) overrides.value = ethers.parseEther(String(valueEth));
  if (gasLimit != null) overrides.gasLimit = BigInt(gasLimit);
  if (nonce != null) overrides.nonce = Number(nonce);
  if (maxFeePerGasGwei != null) overrides.maxFeePerGas = ethers.parseUnits(String(maxFeePerGasGwei), "gwei");
  if (maxPriorityFeePerGasGwei != null) {
    overrides.maxPriorityFeePerGas = ethers.parseUnits(String(maxPriorityFeePerGasGwei), "gwei");
  }

  const fn = contract[method];
  const response = await fn(...args, overrides);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
    gasUsed: receipt?.gasUsed?.toString()
  };
}

export async function estimateContractGas({
  contractAddress,
  abi,
  method,
  args = [],
  valueEth,
  valueWei
}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (!contract[method]?.estimateGas) {
    throw new Error(`Gas estimation not supported for method: ${method}`);
  }

  const overrides = {};
  if (valueWei != null) overrides.value = BigInt(valueWei);
  if (valueEth != null) overrides.value = ethers.parseEther(String(valueEth));

  const gas = await contract[method].estimateGas(...args, overrides);
  return gas.toString();
}

export async function getTransaction(txHash) {
  return await provider.getTransaction(txHash);
}

export async function getTransactionReceipt(txHash) {
  return await provider.getTransactionReceipt(txHash);
}

export async function getCurrentBlockNumber() {
  return await provider.getBlockNumber();
}

export async function waitForTransaction(txHash, confirmations = 1, timeout = 120000) {
  return await provider.waitForTransaction(txHash, confirmations, timeout);
}

export const erc20Abi = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function totalSupply() view returns (uint256)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function transfer(address to, uint256 value) returns (bool)",
  "function approve(address spender, uint256 value) returns (bool)",
  "function transferFrom(address from, address to, uint256 value) returns (bool)",
  "event Transfer(address indexed from, address indexed to, uint256 value)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)"
];

export async function getERC20Balance(tokenAddress, ownerAddress = wallet.address) {
  const token = getContract(tokenAddress, erc20Abi, provider);
  const [balance, decimals, symbol] = await Promise.all([
    token.balanceOf(ownerAddress),
    token.decimals(),
    token.symbol()
  ]);

  return {
    raw: balance.toString(),
    formatted: ethers.formatUnits(balance, decimals),
    decimals: Number(decimals),
    symbol
  };
}

export async function transferERC20({
  tokenAddress,
  to,
  amount,
  decimals
}) {
  if (!tokenAddress) throw new Error("Missing tokenAddress");
  if (!to) throw new Error("Missing recipient address");
  if (amount == null) throw new Error("Missing token amount");

  const token = getContract(tokenAddress, erc20Abi, wallet);
  const tokenDecimals = decimals ?? Number(await token.decimals());
  const parsedAmount = ethers.parseUnits(String(amount), tokenDecimals);

  const response = await token.transfer(to, parsedAmount);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
    gasUsed: receipt?.gasUsed?.toString()
  };
}

